     6→
     7→const TAG_PALETTES = [
     8→  'bg-blue-100 text-blue-700 border-blue-200',
     9→  'bg-violet-100 text-violet-700 border-violet-200',
    10→  'bg-emerald-100 text-emerald-700 border-emerald-200',
    11→  'bg-amber-100 text-amber-800 border-amber-200',
    12→  'bg-rose-100 text-rose-700 border-rose-200',
    13→  'bg-teal-100 text-teal-700 border-teal-200',
    14→  'bg-indigo-100 text-indigo-700 border-indigo-200',
    15→  'bg-orange-100 text-orange-700 border-orange-200',
    16→]
    17→
    18→function tagColor(tag: string): string {
    19→  let hash = 0
    20→  for (let i = 0; i < tag.length; i++) {
    21→    hash = (hash * 31 + tag.charCodeAt(i)) & 0xffffffff
    22→  }
    23→  return TAG_PALETTES[Math.abs(hash) % TAG_PALETTES.length]
    24→}
    25→
    26→function highlight(text: string, query: string): React.ReactNode {
    27→  if (!query.trim()) return text
    28→  const idx = text.toLowerCase().indexOf(query.toLowerCase())
    29→  if (idx === -1) return text
    30→  return (
    31→    <>
    32→      {text.slice(0, idx)}
    33→      <mark className="bg-amber-100 text-amber-800 rounded-sm">{text.slice(idx, idx + query.length)}</mark>
    34→      {text.slice(idx + query.length)}
    35→    </>
    36→  )
    37→}
    38→
    39→function excerpt(text: string, query: string, maxLen = 160): string {
    40→  const idx = text.toLowerCase().indexOf(query.toLowerCase())
    41→  if (idx === -1) return text.slice(0, maxLen) + (text.length > maxLen ? '…' : '')
    42→  const start = Math.max(0, idx - 40)
    43→  const end = Math.min(text.length, idx + query.length + 100)
    44→  return (start > 0 ? '…' : '') + text.slice(start, end) + (end < text.length ? '…' : '')
    45→}
    46→
    47→function groupByBook(results: SearchResult[]): Map<string, { title: string; items: SearchResult[] }> {
    48→  const map = new Map<string, { title: string; items: SearchResult[] }>()
    49→  for (const r of results) {
    50→    if (!map.has(r.bookId)) {
    51→      map.set(r.bookId, { title: r.bookTitle, items: [] })
    52→    }
    53→    map.get(r.bookId)!.items.push(r)
    54→  }
    55→  return map
    56→}
    57→
    58→function groupTagResultsByBook(quotes: (Quote & { book: Book })[]): Map<string, { title: string; quotes: (Quote & { book: Book })[] }> {
    59→  const map = new Map<string, { title: string; quotes: (Quote & { book: Book })[] }>()
    60→  for (const q of quotes) {
    61→    if (!map.has(q.book_id)) {
    62→      map.set(q.book_id, { title: q.book.title, quotes: [] })
    63→    }
    64→    map.get(q.book_id)!.quotes.push(q)
    65→  }
    66→  return map
    67→}
    68→
    69→function typeLabel(r: SearchResult): string {
    70→  if (r.type === 'quote') return 'Quote'
    71→  const tab = r.tab ?? 'note'
    72→  if (tab === 'scratch') return 'Brainstorm'
    73→  return tab.charAt(0).toUpperCase() + tab.slice(1)
    74→}
    75→
    76→function typeBadge(r: SearchResult): string {
    77→  if (r.type === 'quote') return 'bg-ember-100 text-ember-700 border-ember-200'
    78→  return 'bg-fog-100 text-fog-600 border-fog-300'
    79→}
