export async function dequeue(id: string): Promise<void> {
  const db = await openDB()
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, 'readwrite')
    tx.objectStore(STORE_NAME).delete(id)
    tx.oncomplete = () => resolve()
    tx.onerror = () => reject(tx.error)
  })
}

export async function getAllOps(): Promise<PendingOp[]> {
  const db = await openDB()
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, 'readonly')
    const req = tx.objectStore(STORE_NAME).getAll()
    req.onsuccess = () =>
      resolve(
        (req.result as PendingOp[]).sort((a, b) => a.timestamp - b.timestamp)
      )
    req.onerror = () => reject(req.error)
  })
}

/** Returns all locally-created books waiting to be synced to Supabase */
export async function getPendingBooks(): Promise<Book[]> {
  const ops = await getAllOps()
  return ops
    .filter((op) => op.method === 'POST' && op.localBook != null)
    .map((op) => op.localBook as Book)
}

/**
 * Replay every queued operation against the live API.
 * Stops at the first network failure so operations stay in order.
 * @param onBookCreated  Called when a POST succeeds, so callers can swap
 *                       the tempId for the real server-assigned ID.
 */
export async function processQueue(
  onBookCreated?: (tempId: string, realBook: Book) => void
): Promise<{ synced: number; failed: number }> {
  const ops = await getAllOps()
  let synced = 0
  let failed = 0

  for (const op of ops) {
    try {
      const res = await fetch(op.url, {
        method: op.method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(op.body),
      })

      if (res.ok) {
        if (op.method === 'POST' && op.tempId && onBookCreated) {
          const data = await res.json().catch(() => ({}))
          const realBook: Book = data?.book ?? data
          if (realBook?.id) onBookCreated(op.tempId, realBook)
        }
        await dequeue(op.id)
        synced++
      } else {
        // Server rejected the request (e.g. validation error) — discard it
        // to avoid it blocking later operations forever
        await dequeue(op.id)
        failed++
      }
    } catch {
      // Network still down — stop here; the queue stays intact
      failed++
      break
    }
  }

  return { synced, failed }
}

