'use client'

import { useEffect, useState, useCallback } from 'react'
import { processQueue, getAllOps } from '@/lib/syncQueue'

interface PWAProviderProps {
  children: React.ReactNode
}

export default function PWAProvider({ children }: PWAProviderProps) {
  const [isOnline, setIsOnline] = useState(true)
  const [pendingCount, setPendingCount] = useState(0)
  const [syncing, setSyncing] = useState(false)

  const refreshPendingCount = useCallback(async () => {
    const ops = await getAllOps()
    setPendingCount(ops.length)
  }, [])

  const runSync = useCallback(async () => {
    const ops = await getAllOps()
    if (ops.length === 0) return

    setSyncing(true)
    await processQueue()
    setSyncing(false)
    await refreshPendingCount()

    // Signal page components to refresh data from Supabase
    window.dispatchEvent(new Event('mindwell-synced'))
  }, [refreshPendingCount])

  // Online / offline detection
  useEffect(() => {
    setIsOnline(navigator.onLine)

    function handleOnline() {
      setIsOnline(true)
      runSync()
    }
    function handleOffline() {
      setIsOnline(false)
    }

    window.addEventListener('online', handleOnline)
    window.addEventListener('offline', handleOffline)
    return () => {
      window.removeEventListener('online', handleOnline)
      window.removeEventListener('offline', handleOffline)
    }
  }, [runSync])

  // Listen for service worker background-sync messages
  useEffect(() => {
    if (!('serviceWorker' in navigator)) return
    function handleMessage(e: MessageEvent) {
      if (e.data?.type === 'PROCESS_SYNC_QUEUE') runSync()
    }
    navigator.serviceWorker.addEventListener('message', handleMessage)
    return () => navigator.serviceWorker.removeEventListener('message', handleMessage)
  }, [runSync])

  // Register the service worker (production only; dev uses HMR)
  useEffect(() => {
    if ('serviceWorker' in navigator && process.env.NODE_ENV === 'production') {
      navigator.serviceWorker
        .register('/sw.js')
        .catch((err) => console.error('[SW] Registration failed:', err))
    }
  }, [])

  // Re-count whenever the page gains visibility (e.g. tab switch)
  useEffect(() => {
    refreshPendingCount()
    window.addEventListener('mindwell-queue-updated', refreshPendingCount)
    return () => window.removeEventListener('mindwell-queue-updated', refreshPendingCount)
  }, [refreshPendingCount])

  const showBanner = !isOnline || pendingCount > 0

  return (
    <>
      {children}

      {showBanner && (
        <div
          className={[
            'fixed bottom-4 left-1/2 -translate-x-1/2 z-50',
            'flex items-center gap-2.5 px-4 py-2.5 rounded-full',
            'text-sm font-medium shadow-lg pointer-events-none',
            'transition-all duration-300',
            !isOnline
              ? 'bg-amber-500 text-white'
              : 'bg-navy-700 text-white',
          ].join(' ')}
        >
          {!isOnline ? (
            <>
              <span className="w-2 h-2 rounded-full bg-white/70 animate-pulse shrink-0" />
              Offline — changes will sync when you reconnect
            </>
          ) : syncing ? (
            <>
              <span className="w-2 h-2 rounded-full bg-green-300 animate-pulse shrink-0" />
              Syncing {pendingCount} change{pendingCount !== 1 ? 's' : ''}…
            </>
          ) : (
            <>
              <span className="w-2 h-2 rounded-full bg-yellow-300 shrink-0" />
              {pendingCount} pending change{pendingCount !== 1 ? 's' : ''} — waiting to sync
            </>
          )}
        </div>
      )}
    </>
  )
}

