'use client'

import { Suspense, useState, useEffect, useCallback } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import { format, parseISO } from 'date-fns'
import { supabase } from '@/lib/supabase'
import { cacheBooks, getCachedBooks } from '@/lib/localCache'
import { getPendingBooks, processQueue } from '@/lib/syncQueue'
import {
  DndContext,
  closestCenter,
  DragEndEvent,
  DragOverlay,
  DragStartEvent,
  PointerSensor,
  useDroppable,
  useSensor,
  useSensors,
} from '@dnd-kit/core'
import {
  SortableContext,
  useSortable,
  verticalListSortingStrategy,
  arrayMove,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import AddItemModal from '@/components/AddItemModal'
import DetailModal from '@/components/DetailModal'
import GlobalSearch from '@/components/GlobalSearch'
import type { Book } from '@/types'

const READING_SECTION = '__reading-now__'
const QUEUE_SECTION = '__next-up__'

// ── Drag handle ────────────────────────────────────────────────────────────────

function DragHandle() {
  return (
    <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
      <circle cx="4" cy="3" r="1.5" />
      <circle cx="8" cy="3" r="1.5" />
      <circle cx="4" cy="8" r="1.5" />
      <circle cx="8" cy="8" r="1.5" />
      <circle cx="4" cy="13" r="1.5" />
      <circle cx="8" cy="13" r="1.5" />
    </svg>
  )
}

// ── Complete check button ──────────────────────────────────────────────────────

function CompleteButton({ onClick, loading = false }: { onClick: () => void; loading?: boolean }) {
  return (
    <button
      onClick={e => { e.stopPropagation(); onClick() }}
      disabled={loading}
      className="w-7 h-7 flex items-center justify-center rounded-full text-fog-400 hover:text-white hover:bg-navy-700 transition-all disabled:opacity-40 shrink-0"
      title="Mark complete"
    >
      {loading ? (
        <span className="text-[10px]">…</span>
      ) : (
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
          <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
        </svg>
      )}
    </button>
  )
}

// ── Sortable book row (Reading Now / Next Up) ──────────────────────────────────

function SortableBookRow({
  book,
  onOpenDetail,
  onComplete,
  onMoveUp,
}: {
  book: Book
  onOpenDetail: () => void
  onComplete: (book: Book) => void
  onMoveUp?: () => void
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: book.id,
  })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.3 : 1,
  }

  const pct = book.total_pages && book.total_pages > 0
    ? Math.round(((book.current_page ?? 0) / book.total_pages) * 100)
    : 0
  const isQueued = book.status === 'queued' || book.status === 'paused'

  return (
    <div
      ref={setNodeRef}
      style={style}
      className="bg-white rounded-xl border border-fog-300 shadow-sm hover:border-fog-400 hover:shadow-md transition-all flex items-center gap-3 px-3 py-3"
    >
      {/* Drag handle */}
      <button
        {...attributes}
        {...listeners}
        className="text-fog-300 hover:text-fog-500 cursor-grab active:cursor-grabbing shrink-0 touch-none transition-colors"
        aria-label="Drag to reorder"
      >
        <DragHandle />
      </button>

      {/* Clickable content */}
      <button
        onClick={onOpenDetail}
        className="flex-1 min-w-0 text-left"
      >
        <p className="font-medium text-navy-900 truncate text-sm leading-snug">{book.title}</p>
        {book.author && (
          <p className="text-xs text-fog-500 mt-0.5 truncate">{book.author}</p>
        )}
        {!isQueued && book.total_pages && book.total_pages > 0 && (
          <div className="flex items-center gap-2 mt-1.5">
            <div className="w-28 bg-fog-200 rounded-full h-1.5">
              <div
                className="bg-gradient-to-r from-[#a8e063] to-[#2d6a4f] h-1.5 rounded-full transition-all"
                style={{ width: `${pct}%` }}
              />
            </div>
            <span className="text-xs text-fog-400">
              p.{book.current_page ?? 0}/{book.total_pages}
            </span>
          </div>
        )}
      </button>

      {/* Action */}
      {onMoveUp ? (
        <button
          onClick={e => { e.stopPropagation(); onMoveUp() }}
          className="text-xs text-fog-500 hover:text-navy-700 px-2.5 py-1 rounded-full bg-fog-100 hover:bg-navy-100 transition-all shrink-0"
        >
          Start
        </button>
      ) : (
        <CompleteButton onClick={() => onComplete(book)} />
      )}
    </div>
  )
}

